import constFlaskURL from "./constFlaskURL";

export const handleLogout = async (id) => {
    const users = { id, is_active: false };
    const headers = null;

    try {
        await constFlaskURL.post('/logout', users, headers);
    } catch (error) {
        console.error('Logout error:', error);
    }    
};
